def normalize_tts_provider(value: str | None) -> str:
    candidate = str(value or '').strip().lower()
    if candidate in SUPPORTED_TTS_PROVIDERS:
        return candidate
    return DEFAULT_TTS_PROVIDER

def normalize_stt_provider(value: str | None) -> str:
    candidate = str(value or '').strip().lower()
    if candidate in SUPPORTED_STT_PROVIDERS:
        return candidate
    return 'sarvam'

def normalize_voice_mode(value: str | None) -> str:
    candidate = str(value or '').strip().lower()
    if candidate in SUPPORTED_VOICE_MODES:
        return candidate
    return DEFAULT_VOICE_MODE

def normalize_choice(value: str | None, allowed: set[str], default: str) -> str:
    candidate = str(value or '').strip().lower()
    if candidate in allowed:
        return candidate
    return default

def parse_bool(value, default: bool) -> bool:
    if value in (None, ''):
        return default
    if isinstance(value, bool):
        return value
    if isinstance(value, (int, float)):
        return bool(value)
    text = str(value).strip().lower()
    if text in {'1', 'true', 'yes', 'on'}:
        return True
    if text in {'0', 'false', 'no', 'off'}:
        return False
    return default

def parse_float(value, default: float) -> float:
    if value in (None, ''):
        return default
    try:
        return float(value)
    except (TypeError, ValueError):
        return default

def parse_int(value, default: int) -> int:
    if value in (None, ''):
        return default
    try:
        return int(value)
    except (TypeError, ValueError):
        return default

def parse_csv_ints(value, default: list[int]) -> list[int]:
    if value in (None, ''):
        return list(default)
    if isinstance(value, list):
        result = []
        for item in value:
            try:
                result.append(int(item))
            except (TypeError, ValueError):
                continue
        return result or list(default)
    result = []
    for item in str(value).split(','):
        item = item.strip()
        if not item:
            continue
        try:
            result.append(int(float(item)))
        except (TypeError, ValueError):
            continue
    return result or list(default)

