def write_config(data):
    global _CONFIG_CACHE, _CONFIG_CACHE_MTIME
    config = read_config()
    config.update(data)
    config['voice_mode'] = normalize_voice_mode(config.get('voice_mode'))
    config['tts_provider'] = normalize_tts_provider(config.get('tts_provider'))
    config['stt_provider'] = normalize_stt_provider(config.get('stt_provider'))
