@app.get('/api/logs/{log_id}/transcript')
async def api_get_transcript(log_id: str):
    config = read_config()
    configure_supabase_env(config)
    import db
    try:
        from supabase import create_client
        supabase = create_client(os.environ['SUPABASE_URL'], os.environ['SUPABASE_KEY'])
        res = supabase.table('call_logs').select('*').eq('id', log_id).single().execute()
        data = res.data
        text = f"Call Log - {data.get('created_at', '')}\n"
        text += f"Phone: {data.get('phone_number', 'Unknown')}\n"
        text += f"Duration: {data.get('duration_seconds', 0)}s\n"
        text += f"Summary: {data.get('summary', '')}\n\n"
        latency_summary = _summarize_turn_metrics(db.list_call_turn_metrics(call_room_id=data.get('call_room_id'), limit=200))
        if latency_summary:
            text += '--- LATENCY SUMMARY ---\n'
            text += f"Turns: {latency_summary.get('turns', 0)}\n"
            text += f"KB turns: {latency_summary.get('kb_used_turns', 0)}\n"
            for field, label in [('kb_ms', 'KB'), ('llm_first_token_ms', 'LLM first token'), ('tts_first_audio_ms', 'TTS first audio'), ('tool_ms', 'Tool'), ('total_turn_ms', 'Total turn')]:
                if latency_summary.get(field) not in (None, ''):
                    text += f'{label}: {latency_summary[field]} ms avg\n'
            text += '\n'
        text += '--- TRANSCRIPT ---\n'
        text += data.get('transcript', 'No transcript available.')
        return PlainTextResponse(content=text, media_type='text/plain', headers={'Content-Disposition': f'attachment; filename=transcript_{log_id}.txt'})
    except Exception as e:
        logger.error(f'Error fetching transcript {log_id}: {e}')
        return PlainTextResponse(content='Error: Unable to fetch the transcript right now.', status_code=500)

