        data = await request.json()
        payload = {'title': data.get('title'), 'contact_name': data.get('contact_name'), 'contact_phone': data.get('contact_phone'), 'scheduled_start': data.get('scheduled_start'), 'scheduled_end': data.get('scheduled_end'), 'timezone': data.get('timezone') or 'Asia/Kolkata', 'status': data.get('status') or 'scheduled', 'notes': data.get('notes') or '', 'source': 'manual_ui'}
        validate_appointment_payload(payload)
        appointment = db.create_appointment(payload)
        if (appointment.get('status') or 'scheduled') == 'scheduled':
            handle_booking_confirmed(appointment=appointment, caller_name=appointment.get('contact_name') or '', phone_number=appointment.get('contact_phone') or '', ai_summary='Appointment created manually from dashboard.', config=config)
