@app.patch('/api/appointments/{appointment_id}')
async def api_update_appointment(appointment_id: str, request: Request):
    config = read_config()
    configure_supabase_env(config)
    import db
    try:
        data = await request.json()
        current = db.get_appointment(appointment_id)
        payload = {'title': data.get('title'), 'contact_name': data.get('contact_name'), 'contact_phone': data.get('contact_phone'), 'scheduled_start': data.get('scheduled_start'), 'scheduled_end': data.get('scheduled_end'), 'timezone': data.get('timezone'), 'status': data.get('status'), 'notes': data.get('notes')}
        validate_appointment_payload(payload, current=current)
        appointment = db.update_appointment(appointment_id, payload)
        if (appointment.get('status') or '').lower() == 'cancelled':
            handle_appointment_cancelled(appointment, reason='Cancelled from dashboard update.', config=config)
            await asyncio.to_thread(process_due_jobs, limit=10, config=config)
        else:
            handle_appointment_updated(appointment, config=config)
        return {'status': 'ok', 'appointment': appointment}
    except ValueError as e:
        return appointment_error_response(str(e), status_code=400)
    except db.AppointmentNotFoundError as e:
        return appointment_error_response(str(e), status_code=404)
    except db.AppointmentConflictError as e:
        return appointment_error_response(str(e), status_code=409)
    except db.AppointmentValidationError as e:
        return appointment_error_response(str(e), status_code=400)
    except db.AppointmentError as e:
        return appointment_error_response(str(e), status_code=500)
    except Exception as e:
        logger.error(f'Error updating appointment: {e}')
        return appointment_error_response('Unable to update appointment right now.', status_code=500)

