@app.get('/api/contacts')
async def api_get_contacts():
    """CRM endpoint — groups call_logs by phone number, deduplicates into contacts."""
    config = read_config()
    configure_supabase_env(config)
    try:
        import db
        rows = db.fetch_call_logs(limit=500)
        wa_conversations = db.list_wa_conversations(limit=500)
        contacts: dict = {}
        for r in rows:
            phone = r.get('phone_number') or 'unknown'
            if phone not in contacts:
                contacts[phone] = {'phone_number': phone, 'caller_name': r.get('caller_name') or '', 'total_calls': 0, 'last_seen': r.get('created_at'), 'is_booked': False}
            c = contacts[phone]
            c['total_calls'] += 1
            if not c['caller_name'] and r.get('caller_name'):
                c['caller_name'] = r['caller_name']
            if r.get('summary') and 'Confirmed' in r.get('summary', ''):
                c['is_booked'] = True
        for convo in wa_conversations:
            phone = convo.get('phone_number') or 'unknown'
            if phone not in contacts:
                contacts[phone] = {'phone_number': phone, 'caller_name': convo.get('display_name') or '', 'total_calls': 0, 'last_seen': convo.get('last_message_at') or convo.get('updated_at'), 'is_booked': False}
            c = contacts[phone]
            if not c['caller_name'] and convo.get('display_name'):
                c['caller_name'] = convo['display_name']
            if (convo.get('last_message_at') or '') > (c.get('last_seen') or ''):
                c['last_seen'] = convo.get('last_message_at')
            c['whatsapp_unread_count'] = int(convo.get('unread_count') or 0)
            c['whatsapp_last_preview'] = convo.get('last_message_preview') or ''
        return sorted(contacts.values(), key=lambda x: x['last_seen'] or '', reverse=True)
    except Exception as e:
        logger.error(f'Error fetching contacts: {e}')
        return []

