@app.post('/api/automation/jobs')
async def api_automation_job_create(request: Request):
    config = read_config()
    configure_supabase_env(config)
    import db
    try:
        data = await request.json()
        channel = str(data.get('channel') or 'call').strip().lower()
        phone_number = db.normalize_phone_number(data.get('phone_number') or '')
        if not phone_number:
            raise ValueError('phone_number is required.')
        scheduled_for = str(data.get('scheduled_for') or '').strip() or datetime.now(timezone.utc).isoformat()
        caller_name = str(data.get('caller_name') or '').strip()
        trigger_event = str(data.get('trigger_event') or f'manual_{channel}').strip()
        if channel == 'call':
            job = db.create_automation_job({'channel': 'call', 'trigger_event': trigger_event, 'phone_number': phone_number, 'caller_name': caller_name, 'scheduled_for': scheduled_for, 'status': 'pending_review', 'related_call_room_id': str(data.get('related_call_room_id') or '').strip() or None, 'related_appointment_id': data.get('related_appointment_id'), 'payload': data.get('payload') or {}, 'idempotency_key': f'manual-call:{uuid.uuid4().hex}'})
        elif channel == 'whatsapp':
            job = queue_manual_whatsapp(phone_number=phone_number, caller_name=caller_name, template_name=str(data.get('template_name') or '').strip(), body_text=str(data.get('body_text') or '').strip(), message_type=_normalize_message_type(data.get('message_type')), caption=str(data.get('caption') or '').strip(), media_url=str(data.get('media_url') or '').strip(), mime_type=str(data.get('mime_type') or '').strip(), file_name=str(data.get('file_name') or '').strip(), asset_id=data.get('asset_id'), scheduled_for=scheduled_for, metadata=data.get('payload') or {})
        else:
            raise ValueError('Unsupported automation channel.')
        if not job:
            raise RuntimeError('Automation job could not be created.')
        return {'status': 'ok', 'job': job}
    except ValueError as exc:
        return JSONResponse({'status': 'error', 'message': str(exc)}, status_code=400)
    except Exception as exc:
        logger.error(f'Failed to create automation job: {exc}')
        return JSONResponse({'status': 'error', 'message': str(exc)}, status_code=500)

