@app.post('/api/message-assets/upload')
async def api_message_asset_upload(file: UploadFile=File(...)):
    config = read_config()
    configure_supabase_env(config)
    import db
    supabase = db.get_supabase()
    if not supabase:
        return JSONResponse({'status': 'error', 'message': 'Supabase is not configured.'}, status_code=400)
    if not file.filename:
        return JSONResponse({'status': 'error', 'message': 'File name is required.'}, status_code=400)
    try:
        content = await file.read(MAX_MESSAGE_ASSET_BYTES + 1)
        if len(content) > MAX_MESSAGE_ASSET_BYTES:
            return JSONResponse({'status': 'error', 'message': f'File is too large. Max size is {MAX_MESSAGE_ASSET_BYTES // (1024 * 1024)} MB.'}, status_code=400)
        safe_name = re.sub('[^a-zA-Z0-9._-]', '_', file.filename)
        path = f"{datetime.now(timezone.utc).strftime('%Y/%m')}/{uuid.uuid4().hex}_{safe_name}"
        mime_type = file.content_type or mimetypes.guess_type(file.filename)[0] or 'application/octet-stream'
        bucket = 'message-assets'
        try:
            supabase.storage.from_(bucket).upload(path, content, {'content-type': mime_type})
        except TypeError:
            supabase.storage.from_(bucket).upload(path, content, file_options={'content-type': mime_type})
        public_url = None
        try:
            public_url = supabase.storage.from_(bucket).get_public_url(path)
            if isinstance(public_url, dict):
                public_url = public_url.get('publicUrl') or public_url.get('publicURL') or (public_url.get('data') or {}).get('publicUrl')
        except Exception:
            base = str(config.get('supabase_url') or '').rstrip('/')
            if base:
                public_url = f'{base}/storage/v1/object/public/{bucket}/{path}'
        asset = db.create_message_asset({'name': safe_name, 'bucket': bucket, 'path': path, 'public_url': public_url or '', 'mime_type': mime_type, 'size_bytes': len(content), 'metadata': {'original_name': file.filename}})
        if not asset:
            raise RuntimeError('Asset metadata could not be saved.')
        return {'status': 'ok', 'asset': asset}
    except Exception as exc:
        logger.error(f'Failed to upload message asset: {exc}')
        return JSONResponse({'status': 'error', 'message': str(exc)}, status_code=500)
