    ui_host = str(os.environ.get('UI_HOST', '0.0.0.0')).strip() or '0.0.0.0'
    ui_port = parse_int(os.environ.get('UI_PORT'), 8000)
    ui_reload = parse_bool(os.environ.get('UI_RELOAD'), False)
    uvicorn.run('ui_server:app', host=ui_host, port=ui_port, reload=ui_reload)
